def get_char_ngrams(word, n=3):
    extended_word = '<' + word + '>'
    return [extended_word[i:i+n] for i in range(len(extended_word)-n+1)]

def run_practice():
    ngrams = get_char_ngrams('cat', 3)
    assert '<ca' in ngrams
    assert 'at>' in ngrams
